CREATE OR REPLACE FUNCTION public.update_app_user(
  p_user_id uuid,
  p_email text,
  p_password text,
  p_name text,
  p_role app_role,
  p_phone text DEFAULT NULL::text,
  p_department text DEFAULT NULL::text,
  p_active boolean DEFAULT true
)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  v_actor_role public.app_role;
begin
  select role into v_actor_role from public.profiles where id = auth.uid() and active = true;
  if v_actor_role <> 'admin' then
    raise exception 'Only Admin can update users.';
  end if;

  if p_password is not null and length(p_password) > 0 then
    if length(p_password) < 6 then
      raise exception 'Password must be at least 6 characters.';
    end if;
    update auth.users
    set encrypted_password = extensions.crypt(p_password, extensions.gen_salt('bf')),
        updated_at = now()
    where id = p_user_id;
  end if;

  if p_email is not null and length(p_email) > 0 then
    update auth.users
    set email = lower(p_email),
        updated_at = now()
    where id = p_user_id;

    update auth.identities
    set identity_data = jsonb_set(identity_data, '{email}', to_jsonb(lower(p_email)))
    where user_id = p_user_id and provider = 'email';
  end if;

  update public.profiles
  set name = p_name, role = p_role, phone = p_phone, department = p_department, active = p_active
  where id = p_user_id;

end;
$function$;
